-- ----------------------------
-- Table structure for att_attendance_policy
-- ----------------------------
DROP TABLE IF EXISTS `att_attendance_policy`;
CREATE TABLE `att_attendance_policy`  (
  `id` bigint(20) UNSIGNED NOT NULL AUTO_INCREMENT,
  `policy_code` varchar(40) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `policy_name` varchar(120) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `checkin_open_minutes_before` int(10) UNSIGNED NOT NULL DEFAULT 30,
  `checkout_close_minutes_after` int(10) UNSIGNED NOT NULL DEFAULT 180,
  `enforce_geofence` tinyint(1) NOT NULL DEFAULT 1,
  `require_photo` tinyint(1) NOT NULL DEFAULT 0,
  `pending_request_scope` enum('SELF_ONLY','POSITION_ONLY','SELF_AND_POSITION') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'SELF_ONLY',
  `pending_approval_levels` tinyint(3) UNSIGNED NOT NULL DEFAULT 3,
  `late_deduction_per_minute` decimal(18, 2) NOT NULL DEFAULT 0,
  `enable_late_deduction` tinyint(1) NOT NULL DEFAULT 1,
  `alpha_deduction_per_day` decimal(18, 2) NOT NULL DEFAULT 0,
  `enable_alpha_deduction` tinyint(1) NOT NULL DEFAULT 1,
  `use_basic_salary_daily_rate` tinyint(1) NOT NULL DEFAULT 1,
  `default_work_days_per_month` int(10) UNSIGNED NOT NULL DEFAULT 26,
  `attendance_calc_mode` enum('DAILY','MONTHLY') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'DAILY',
  `payroll_late_deduction_scope` enum('BASIC_ONLY','THP_TOTAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'BASIC_ONLY',
  `prorate_deduction_scope` enum('BASIC_ONLY','THP_TOTAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'BASIC_ONLY',
  `allowance_late_treatment` enum('FULL_IF_PRESENT','DEDUCT_IF_LATE') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'FULL_IF_PRESENT',
  `meal_calc_mode` enum('MONTHLY','CUSTOM') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'MONTHLY',
  `overtime_calc_mode` enum('AUTO','MANUAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'AUTO',
  `operation_start_time` time(0) NULL DEFAULT NULL,
  `operation_end_time` time(0) NULL DEFAULT NULL,
  `night_shift_checkout_credit_after` time(0) NULL DEFAULT NULL,
  `night_shift_checkout_credit_to_operation_end` tinyint(1) NOT NULL DEFAULT 1,
  `ph_attendance_mode` enum('AUTO_PRESENT','MANUAL_CLOCK') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'AUTO_PRESENT',
  `ph_grant_mode` enum('SHIFT_ONLY','HOLIDAY_ONLY','SHIFT_OR_HOLIDAY') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'HOLIDAY_ONLY',
  `ph_grant_holiday_type` enum('ANY','NATIONAL','COMPANY','SPECIAL') CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL DEFAULT 'ANY',
  `ph_grant_requires_checkout` tinyint(1) NOT NULL DEFAULT 1,
  `ph_grant_qty_per_day` decimal(6, 2) NOT NULL DEFAULT 1,
  `ph_auto_presence_on_open` tinyint(1) NOT NULL DEFAULT 1,
  `ph_requires_clock_in_out` tinyint(1) NOT NULL DEFAULT 0,
  `ph_expiry_months` int(10) UNSIGNED NOT NULL DEFAULT 3,
  `ph_gets_meal_allowance` tinyint(1) NOT NULL DEFAULT 0,
  `ph_gets_bonus` tinyint(1) NOT NULL DEFAULT 0,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` datetime(0) NOT NULL DEFAULT current_timestamp(0),
  `updated_at` datetime(0) NULL DEFAULT NULL ON UPDATE CURRENT_TIMESTAMP(0),
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_att_attendance_policy_code`(`policy_code`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

