INSERT INTO `hr_contract` VALUES (8, 'NCE/K1/001/2026', 18, 1, NULL, 'K1', 'ACTIVE', 'COOK', 'KITCHEN', 1400000.00, 200000.00, 0.00, 0.00, 5982.91, '2026-03-01', '2026-06-01', 'e46fde23531fcaf1ef7f44c7ee3fc921', 'd4ab7e67d7c7676385d917c3b4333b0811637891e28c1f17461324c3ac0737b1', '2026-04-03 16:48:12', '<div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 1 &mdash; Masa Training (3 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 3 April 2026, telah disepakati dan ditandatangani Perjanjian Kerja Waktu Tertentu (PKWT) oleh dan antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>AHMAD SETIAWAN</strong>, dengan jabatan <strong>COOK</strong> pada divisi <strong>KITCHEN</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Para pihak sepakat untuk membuat perjanjian kerja dengan ketentuan sebagai berikut:</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 1 (Masa Training)</strong> untuk jabatan <strong>COOK</strong> di divisi <strong>KITCHEN</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>3 bulan</strong>, terhitung sejak <strong>1 Maret 2026</strong> hingga <strong>1 Juni 2026</strong>.</li><li style=\"margin-bottom:5px\">Masa training merupakan periode uji kelayakan. Selama masa ini, PERUSAHAAN berhak mengakhiri perjanjian kerja sewaktu-waktu dengan memberikan pemberitahuan tertulis kepada PEGAWAI.</li><li style=\"margin-bottom:5px\">Pada akhir masa kontrak, PERUSAHAAN melakukan evaluasi kinerja. Hasil evaluasi menentukan kelanjutan hubungan kerja ke Kontrak 2.</li><li style=\"margin-bottom:5px\">Tidak ada kewajiban dari PERUSAHAAN untuk melanjutkan hubungan kerja setelah masa kontrak berakhir.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\n        </tr>\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 200.000</strong> / bulan</td>\n        </tr>\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\n        </tr>\n        <tr style=\"background:#e8f0fe\">\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.400.000</strong> / bulan</td>\n        </tr>\n      </table></li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1&ndash;3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan secara proporsional berdasarkan masa kerja aktual pada kontrak ini.</li><li style=\"margin-bottom:5px\">Review kompensasi dari Kontrak 1 ke Kontrak 2 dilakukan berdasarkan hasil evaluasi &mdash; tidak berlaku otomatis.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5&times;</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas dari diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan pelatihan dasar yang diperlukan untuk pelaksanaan tugas.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan dan hasil evaluasi sebelum berakhirnya masa kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan &rarr; teguran tertulis &rarr; Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 500.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>1 Juni 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-03 16:48:12', 67, '2026-04-03 16:48:12', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (9, 'NCE/K1/002/2026', 52, 1, NULL, 'K1', 'ACTIVE', 'BARISTA', 'BAR', 1200000.00, 0.00, 0.00, 0.00, 8000.00, '2026-03-28', '2026-06-28', '79bfa1389ae123510b028c27c0c33776', '834f8c646a0d5896e71584373cabbdfc8a8494c53eb8ccc4a52cade1dfb75b8a', '2026-04-03 17:01:21', '<div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 1 &mdash; Masa Training (3 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 3 April 2026, telah disepakati dan ditandatangani Perjanjian Kerja Waktu Tertentu (PKWT) oleh dan antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>NAYLA SYAHFIQAH</strong>, dengan jabatan <strong>BARISTA</strong> pada divisi <strong>BAR</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Para pihak sepakat untuk membuat perjanjian kerja dengan ketentuan sebagai berikut:</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 1 (Masa Training)</strong> untuk jabatan <strong>BARISTA</strong> di divisi <strong>BAR</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>3 bulan</strong>, terhitung sejak <strong>28 Maret 2026</strong> hingga <strong>28 Juni 2026</strong>.</li><li style=\"margin-bottom:5px\">Masa training merupakan periode uji kelayakan. Selama masa ini, PERUSAHAAN berhak mengakhiri perjanjian kerja sewaktu-waktu dengan memberikan pemberitahuan tertulis kepada PEGAWAI.</li><li style=\"margin-bottom:5px\">Pada akhir masa kontrak, PERUSAHAAN melakukan evaluasi kinerja. Hasil evaluasi menentukan kelanjutan hubungan kerja ke Kontrak 2.</li><li style=\"margin-bottom:5px\">Tidak ada kewajiban dari PERUSAHAAN untuk melanjutkan hubungan kerja setelah masa kontrak berakhir.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\n        </tr>\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\n        </tr>\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\n        </tr>\n        <tr style=\"background:#e8f0fe\">\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.200.000</strong> / bulan</td>\n        </tr>\n      </table></li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1&ndash;3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan secara proporsional berdasarkan masa kerja aktual pada kontrak ini.</li><li style=\"margin-bottom:5px\">Review kompensasi dari Kontrak 1 ke Kontrak 2 dilakukan berdasarkan hasil evaluasi &mdash; tidak berlaku otomatis.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5&times;</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas dari diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan pelatihan dasar yang diperlukan untuk pelaksanaan tugas.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan dan hasil evaluasi sebelum berakhirnya masa kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan &rarr; teguran tertulis &rarr; Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 500.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>28 Juni 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-03 17:01:21', 67, '2026-04-03 17:01:21', '2026-05-08 01:02:11');
INSERT INTO `hr_contract` VALUES (10, 'NCE/K1/003/2026', 53, 1, NULL, 'K1', 'SIGNED', 'COOK', 'KITCHEN', 1400000.00, 200000.00, 0.00, 0.00, 8000.00, '2026-04-22', '2026-07-22', 'a2f377920368c10ac3e1c5d180caaae2', '3211aebb4fc11f93d2521fea46437abd933a528bec8cc78c35eff5d1ddd0f22c', '2026-04-22 16:23:27', '<div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 1 &mdash; Masa Training (3 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 22 April 2026, telah disepakati dan ditandatangani Perjanjian Kerja Waktu Tertentu (PKWT) oleh dan antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>SITI RHIMAH</strong>, dengan jabatan <strong>COOK</strong> pada divisi <strong>KITCHEN</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Para pihak sepakat untuk membuat perjanjian kerja dengan ketentuan sebagai berikut:</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 1 (Masa Training)</strong> untuk jabatan <strong>COOK</strong> di divisi <strong>KITCHEN</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>3 bulan</strong>, terhitung sejak <strong>22 April 2026</strong> hingga <strong>22 Juli 2026</strong>.</li><li style=\"margin-bottom:5px\">Masa training merupakan periode uji kelayakan. Selama masa ini, PERUSAHAAN berhak mengakhiri perjanjian kerja sewaktu-waktu dengan memberikan pemberitahuan tertulis kepada PEGAWAI.</li><li style=\"margin-bottom:5px\">Pada akhir masa kontrak, PERUSAHAAN melakukan evaluasi kinerja. Hasil evaluasi menentukan kelanjutan hubungan kerja ke Kontrak 2.</li><li style=\"margin-bottom:5px\">Tidak ada kewajiban dari PERUSAHAAN untuk melanjutkan hubungan kerja setelah masa kontrak berakhir.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\n        </tr>\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 200.000</strong> / bulan</td>\n        </tr>\n        <tr>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\n        </tr>\n        <tr style=\"background:#e8f0fe\">\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.400.000</strong> / bulan</td>\n        </tr>\n      </table></li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1&ndash;3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan secara proporsional berdasarkan masa kerja aktual pada kontrak ini.</li><li style=\"margin-bottom:5px\">Review kompensasi dari Kontrak 1 ke Kontrak 2 dilakukan berdasarkan hasil evaluasi &mdash; tidak berlaku otomatis.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5&times;</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas dari diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan pelatihan dasar yang diperlukan untuk pelaksanaan tugas.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan dan hasil evaluasi sebelum berakhirnya masa kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan &rarr; teguran tertulis &rarr; Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 500.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>22 Juli 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-22 16:23:27', 67, '2026-04-22 16:23:27', '2026-05-08 08:10:57');
INSERT INTO `hr_contract` VALUES (11, 'NCE/K3/001/2025', 4, 3, NULL, 'K3', 'SIGNED', 'PURCHASING', 'MANAJEMEN', 2000000.00, 600000.00, 0.00, 8000.00, 8000.00, '2025-10-14', '2026-10-14', '393923e88d335cf9a22077f6aeb77f63', '4e5263b913e14377efa91dc7fd62421b325600c314098aabaa9ca8190c440888', '2026-04-24 17:56:05', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 3 — Penuh (12 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 24 April 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>CAROLUS ALOYSIUS E.S</strong>, dengan jabatan <strong>PURCHASING</strong> pada divisi <strong>MANAJEMEN</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 2</strong> (No. K3) setelah PEGAWAI dinyatakan <strong>lulus evaluasi</strong>. Total masa kerja kumulatif: ± 9 bulan. Penyelesaian Kontrak 3 dengan baik menjadi dasar pertimbangan pengangkatan sebagai <strong>Pegawai Tetap (PKWTT)</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 3 (Penuh)</strong> untuk jabatan <strong>PURCHASING</strong> di divisi <strong>MANAJEMEN</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>12 bulan</strong>, terhitung sejak <strong>14 Oktober 2025</strong> hingga <strong>14 Oktober 2026</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6 (tengah tahun) dan bulan ke-12 (akhir tahun).</li><li style=\"margin-bottom:5px\">Berdasarkan hasil evaluasi akhir, PERUSAHAAN berhak: mengangkat PEGAWAI sebagai pegawai tetap, memperpanjang Kontrak 3, atau tidak memperpanjang dengan pemberitahuan minimum 30 hari.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.400.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 600.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 2.000.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 8.000</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan&nbsp;berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dilakukan di akhir masa kontrak berdasarkan hasil evaluasi kinerja.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li><li style=\"margin-bottom:5px\">Cuti Melahirkan: 3 (tiga) bulan bagi PEGAWAI perempuan, sesuai ketentuan UU Ketenagakerjaan. Kompensasi selama cuti melahirkan mengacu pada peraturan perusahaan yang berlaku.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Berperan aktif sebagai role model bagi pegawai baru (Kontrak 1 dan 2).</li><li style=\"margin-bottom:5px\">Jabatan strategis (Barista Senior, Head Cook, Supervisor, HOD): tidak bekerja pada bisnis F&amp;B sejenis dalam radius 5 km selama 3 bulan setelah berakhirnya perjanjian.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap, uang makan, PH, dan lembur tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan THR sesuai ketentuan Pasal 3.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan review kompensasi di akhir masa kontrak.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak diperpanjang.</li><li style=\"margin-bottom:5px\">Mendapatkan pertimbangan terbuka untuk pengangkatan sebagai pegawai tetap.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 1.000.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>14 Oktober 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK akibat force majeure atau efisiensi: PERUSAHAAN memberikan kompensasi sesuai PP No. 35/2021 Pasal 43–44.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 17:56:04', 67, '2026-04-24 17:56:04', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (12, 'NCE/K3/001/2026', 6, 3, NULL, 'K3', 'SIGNED', 'HEADBAR', 'BAR', 2000000.00, 600000.00, 0.00, 8000.00, 8000.00, '2026-01-11', '2027-01-11', 'b554be8517f2f8fbf56f97e18311e026', '8d0773a64b94a4d49c41e986bdff905cd61df4dd6a4293ef2e9638d71c857a86', '2026-04-24 17:57:37', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 3 — Penuh (12 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 24 April 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>EKO BUDI LESTARI</strong>, dengan jabatan <strong>HEADBAR</strong> pada divisi <strong>BAR</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 2</strong> (No. K3) setelah PEGAWAI dinyatakan <strong>lulus evaluasi</strong>. Total masa kerja kumulatif: ± 9 bulan. Penyelesaian Kontrak 3 dengan baik menjadi dasar pertimbangan pengangkatan sebagai <strong>Pegawai Tetap (PKWTT)</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 3 (Penuh)</strong> untuk jabatan <strong>HEADBAR</strong> di divisi <strong>BAR</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>12 bulan</strong>, terhitung sejak <strong>11 Januari 2026</strong> hingga <strong>11 Januari 2027</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6 (tengah tahun) dan bulan ke-12 (akhir tahun).</li><li style=\"margin-bottom:5px\">Berdasarkan hasil evaluasi akhir, PERUSAHAAN berhak: mengangkat PEGAWAI sebagai pegawai tetap, memperpanjang Kontrak 3, atau tidak memperpanjang dengan pemberitahuan minimum 30 hari.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.400.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 600.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 2.000.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 8.000</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan&nbsp;berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dilakukan di akhir masa kontrak berdasarkan hasil evaluasi kinerja.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li><li style=\"margin-bottom:5px\">Cuti Melahirkan: 3 (tiga) bulan bagi PEGAWAI perempuan, sesuai ketentuan UU Ketenagakerjaan. Kompensasi selama cuti melahirkan mengacu pada peraturan perusahaan yang berlaku.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Berperan aktif sebagai role model bagi pegawai baru (Kontrak 1 dan 2).</li><li style=\"margin-bottom:5px\">Jabatan strategis (Barista Senior, Head Cook, Supervisor, HOD): tidak bekerja pada bisnis F&amp;B sejenis dalam radius 5 km selama 3 bulan setelah berakhirnya perjanjian.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap, uang makan, PH, dan lembur tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan THR sesuai ketentuan Pasal 3.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan review kompensasi di akhir masa kontrak.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak diperpanjang.</li><li style=\"margin-bottom:5px\">Mendapatkan pertimbangan terbuka untuk pengangkatan sebagai pegawai tetap.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 1.000.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>11 Januari 2027</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK akibat force majeure atau efisiensi: PERUSAHAAN memberikan kompensasi sesuai PP No. 35/2021 Pasal 43–44.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 17:57:37', 67, '2026-04-24 17:57:37', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (13, 'NCE/K3/002/2025', 9, 3, NULL, 'K3', 'SIGNED', 'BARISTA', 'BAR', 1400000.00, 0.00, 200000.00, 8000.00, 8000.00, '2025-10-11', '2026-10-11', '338896a4f198a7749e41c05eb681314e', 'b479657db5f6a6fc9f5f02e5adc268dc9aa2ab92963efd0bf5861c2034afbbad', '2026-04-24 17:58:52', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 3 — Penuh (12 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 24 April 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>FAIRUZ SABRI RAFIF</strong>, dengan jabatan <strong>BARISTA</strong> pada divisi <strong>BAR</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 2</strong> (No. K3) setelah PEGAWAI dinyatakan <strong>lulus evaluasi</strong>. Total masa kerja kumulatif: ± 9 bulan. Penyelesaian Kontrak 3 dengan baik menjadi dasar pertimbangan pengangkatan sebagai <strong>Pegawai Tetap (PKWTT)</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 3 (Penuh)</strong> untuk jabatan <strong>BARISTA</strong> di divisi <strong>BAR</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>12 bulan</strong>, terhitung sejak <strong>11 Oktober 2025</strong> hingga <strong>11 Oktober 2026</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6 (tengah tahun) dan bulan ke-12 (akhir tahun).</li><li style=\"margin-bottom:5px\">Berdasarkan hasil evaluasi akhir, PERUSAHAAN berhak: mengangkat PEGAWAI sebagai pegawai tetap, memperpanjang Kontrak 3, atau tidak memperpanjang dengan pemberitahuan minimum 30 hari.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 200.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.400.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 8.000</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan&nbsp;berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dilakukan di akhir masa kontrak berdasarkan hasil evaluasi kinerja.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li><li style=\"margin-bottom:5px\">Cuti Melahirkan: 3 (tiga) bulan bagi PEGAWAI perempuan, sesuai ketentuan UU Ketenagakerjaan. Kompensasi selama cuti melahirkan mengacu pada peraturan perusahaan yang berlaku.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Berperan aktif sebagai role model bagi pegawai baru (Kontrak 1 dan 2).</li><li style=\"margin-bottom:5px\">Jabatan strategis (Barista Senior, Head Cook, Supervisor, HOD): tidak bekerja pada bisnis F&amp;B sejenis dalam radius 5 km selama 3 bulan setelah berakhirnya perjanjian.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap, uang makan, PH, dan lembur tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan THR sesuai ketentuan Pasal 3.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan review kompensasi di akhir masa kontrak.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak diperpanjang.</li><li style=\"margin-bottom:5px\">Mendapatkan pertimbangan terbuka untuk pengangkatan sebagai pegawai tetap.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 1.000.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>11 Oktober 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK akibat force majeure atau efisiensi: PERUSAHAAN memberikan kompensasi sesuai PP No. 35/2021 Pasal 43–44.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 17:58:52', 67, '2026-04-24 17:58:52', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (14, 'NCE/K3/003/2025', 11, 3, NULL, 'K3', 'DRAFT', 'DEMI CHEF DE PARTIE', 'KITCHEN', 1800000.00, 500000.00, 100000.00, 8000.00, 8000.00, '2026-01-11', '2027-01-11', '8132cba4d28b9849243f45e238705574', '27498654bd6556b96645de6c1fed4e3f0c22b0dba6bcf7ba9922bc9fd968882b', '2026-04-24 18:00:10', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 3 — Penuh (12 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 1 Mei 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>FADILLA HARTONO PUTRI</strong>, dengan jabatan <strong>DEMI CHEF DE PARTIE</strong> pada divisi <strong>KITCHEN</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 2</strong> (No. K3) setelah PEGAWAI dinyatakan <strong>lulus evaluasi</strong>. Total masa kerja kumulatif: ± 9 bulan. Penyelesaian Kontrak 3 dengan baik menjadi dasar pertimbangan pengangkatan sebagai <strong>Pegawai Tetap (PKWTT)</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 3 (Penuh)</strong> untuk jabatan <strong>DEMI CHEF DE PARTIE</strong> di divisi <strong>KITCHEN</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>12 bulan</strong>, terhitung sejak <strong>11 Januari 2026</strong> hingga <strong>11 Januari 2027</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6 (tengah tahun) dan bulan ke-12 (akhir tahun).</li><li style=\"margin-bottom:5px\">Berdasarkan hasil evaluasi akhir, PERUSAHAAN berhak: mengangkat PEGAWAI sebagai pegawai tetap, memperpanjang Kontrak 3, atau tidak memperpanjang dengan pemberitahuan minimum 30 hari.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 500.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 100.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.800.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 8.000</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan&nbsp;berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dilakukan di akhir masa kontrak berdasarkan hasil evaluasi kinerja.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li><li style=\"margin-bottom:5px\">Cuti Melahirkan: 3 (tiga) bulan bagi PEGAWAI perempuan, sesuai ketentuan UU Ketenagakerjaan. Kompensasi selama cuti melahirkan mengacu pada peraturan perusahaan yang berlaku.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Berperan aktif sebagai role model bagi pegawai baru (Kontrak 1 dan 2).</li><li style=\"margin-bottom:5px\">Jabatan strategis (Barista Senior, Head Cook, Supervisor, HOD): tidak bekerja pada bisnis F&amp;B sejenis dalam radius 5 km selama 3 bulan setelah berakhirnya perjanjian.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap, uang makan, PH, dan lembur tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan THR sesuai ketentuan Pasal 3.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan review kompensasi di akhir masa kontrak.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak diperpanjang.</li><li style=\"margin-bottom:5px\">Mendapatkan pertimbangan terbuka untuk pengangkatan sebagai pegawai tetap.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 1.000.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>11 Januari 2027</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK akibat force majeure atau efisiensi: PERUSAHAAN memberikan kompensasi sesuai PP No. 35/2021 Pasal 43–44.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 18:00:09', 67, '2026-04-24 18:00:09', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (15, 'NCE/K2/001/2026', 13, 2, NULL, 'K2', 'SIGNED', 'COOK HELPER', 'KITCHEN', 1400000.00, 0.00, 200000.00, 8000.00, 8000.00, '2026-01-11', '2026-07-11', '7931c7b04cff9dac8d61d617a91b6b62', 'aac5d34e48352dc654bf24089089287794ae847713717c305513d83bd75dd658', '2026-04-24 18:01:11', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 2 — Lanjutan (6 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 24 April 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) Lanjutan antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>NUR AISYAH IRVANA PUTRI</strong>, dengan jabatan <strong>COOK HELPER</strong> pada divisi <strong>KITCHEN</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 1</strong> (No. K2) setelah PEGAWAI dinyatakan <strong>lulus evaluasi masa training</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 2 (Lanjutan)</strong> untuk jabatan <strong>COOK HELPER</strong> di divisi <strong>KITCHEN</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>6 bulan</strong>, terhitung sejak <strong>11 Januari 2026</strong> hingga <strong>11 Juli 2026</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6. Hasil evaluasi menentukan kelanjutan ke Kontrak 3.</li><li style=\"margin-bottom:5px\">Kriteria evaluasi: kinerja (KPI), kehadiran, disiplin, kemampuan kerja tim, dan perkembangan kompetensi.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 200.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.400.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 8.000</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan secara proporsional berdasarkan masa kerja kumulatif berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dari Kontrak 2 ke Kontrak 3 dilakukan berdasarkan hasil evaluasi — tidak berlaku otomatis.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam. (meningkat dari Kontrak 1)</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Bersedia membantu pelatihan pegawai baru (Kontrak 1) di bawah supervisi atasan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap dan uang makan tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan pelatihan/pengembangan kompetensi yang relevan dengan jabatan.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan evaluasi dan hasilnya secara tertulis.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak akan diperpanjang.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 750.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>11 Juli 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK karena pelanggaran berat dapat dilakukan seketika tanpa pemberitahuan dan kompensasi.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 18:01:10', 67, '2026-04-24 18:01:10', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (16, 'NCE/K3/001/2024', 3, 3, NULL, 'K3', 'SIGNED', 'SUPERVISOR', 'MANAJEMEN', 2700000.00, 1300000.00, 0.00, 8000.00, 8000.00, '2024-02-18', '2026-08-18', 'ad629584c21f1bcde46f484fe0e865f2', '028685367e5000ce1bc36dc9fe435ebd3ab4a45dea29c4c32e92e66f9c2ed2e5', '2026-04-24 18:02:56', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 3 — Penuh (12 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 24 April 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>BAGAS BHAKTI .R</strong>, dengan jabatan <strong>SUPERVISOR</strong> pada divisi <strong>MANAJEMEN</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 2</strong> (No. K3) setelah PEGAWAI dinyatakan <strong>lulus evaluasi</strong>. Total masa kerja kumulatif: ± 9 bulan. Penyelesaian Kontrak 3 dengan baik menjadi dasar pertimbangan pengangkatan sebagai <strong>Pegawai Tetap (PKWTT)</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 3 (Penuh)</strong> untuk jabatan <strong>SUPERVISOR</strong> di divisi <strong>MANAJEMEN</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>12 bulan</strong>, terhitung sejak <strong>18 Februari 2024</strong> hingga <strong>18 Agustus 2026</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6 (tengah tahun) dan bulan ke-12 (akhir tahun).</li><li style=\"margin-bottom:5px\">Berdasarkan hasil evaluasi akhir, PERUSAHAAN berhak: mengangkat PEGAWAI sebagai pegawai tetap, memperpanjang Kontrak 3, atau tidak memperpanjang dengan pemberitahuan minimum 30 hari.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.400.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.300.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 2.700.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 8.000</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan&nbsp;berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dilakukan di akhir masa kontrak berdasarkan hasil evaluasi kinerja.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam.</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li><li style=\"margin-bottom:5px\">Cuti Melahirkan: 3 (tiga) bulan bagi PEGAWAI perempuan, sesuai ketentuan UU Ketenagakerjaan. Kompensasi selama cuti melahirkan mengacu pada peraturan perusahaan yang berlaku.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Berperan aktif sebagai role model bagi pegawai baru (Kontrak 1 dan 2).</li><li style=\"margin-bottom:5px\">Jabatan strategis (Barista Senior, Head Cook, Supervisor, HOD): tidak bekerja pada bisnis F&amp;B sejenis dalam radius 5 km selama 3 bulan setelah berakhirnya perjanjian.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap, uang makan, PH, dan lembur tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan THR sesuai ketentuan Pasal 3.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan review kompensasi di akhir masa kontrak.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak diperpanjang.</li><li style=\"margin-bottom:5px\">Mendapatkan pertimbangan terbuka untuk pengangkatan sebagai pegawai tetap.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 1.000.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>18 Agustus 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK akibat force majeure atau efisiensi: PERUSAHAAN memberikan kompensasi sesuai PP No. 35/2021 Pasal 43–44.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 18:02:56', 67, '2026-04-24 18:02:56', '2026-05-07 23:53:51');
INSERT INTO `hr_contract` VALUES (17, 'NCE/K2/001/2025', 15, 2, NULL, 'K2', 'SIGNED', 'PARTTIME BARISTA', 'BAR', 1404000.00, 204000.00, 0.00, 0.00, 8000.00, '2025-10-08', '2026-04-08', '487684151e7f127c32f390612fb8176e', 'e3bf5b103f5386888185d9f178719c2795cdd571cd48078638d06ed969afdd7a', '2026-04-24 18:04:28', '\r\n                \r\n                \r\n                <div style=\"text-align:center;margin-bottom:20px;padding-bottom:14px;border-bottom:2px solid #222\"><img src=\"https://core.namuacoffee.com/assets/img/logo.png\" alt=\"Namua Coffee\" style=\"height:68px;display:block;margin:0 auto 10px\"><div style=\"font-family:Arial,sans-serif;font-size:16px;font-weight:bold;letter-spacing:1.5px;text-transform:uppercase\">Namua Coffee and Eatery</div><div style=\"font-family:Arial,sans-serif;font-size:13px;color:#555;margin-top:3px\">Jl. Magnolia, Sawah, Kabongan Kidul, Kecamatan Rembang</div><div style=\"font-family:Arial,sans-serif;margin-top:12px;font-size:19px;font-weight:bold;text-transform:uppercase;letter-spacing:.6px\">Perjanjian Kerja Waktu Tertentu</div><div style=\"font-family:Arial,sans-serif;font-size:17px;font-weight:bold;margin-top:2px\">Kontrak 2 — Lanjutan (6 bulan)</div></div><div style=\"font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px;line-height:1.85;color:#1a1a1a\"><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Pada hari ini, 24 April 2026, telah disepakati Perjanjian Kerja Waktu Tertentu (PKWT) Lanjutan antara:</p><table style=\"width:100%;margin-bottom:14px;border-collapse:collapse;font-family:\'Times New Roman\',Times,Georgia,serif;font-size:16px\"><tbody><tr><td style=\"width:28%;padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Pertama</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>Namua Coffee and Eatery</strong>, diwakili oleh <strong>Anis Fitriya</strong> selaku Owner, berkedudukan di Jl. Magnolia, Desa Kabongan Kidul, Kecamatan Rembang. Selanjutnya disebut <strong>PERUSAHAAN</strong>.</td></tr><tr><td style=\"padding:5px 10px;border:1px solid #ccc;background:#f5f5f5;font-weight:bold;vertical-align:top\">Pihak Kedua</td><td style=\"padding:5px 10px;border:1px solid #ccc;vertical-align:top\">: <strong>ALFANDITA AURIEL ANA</strong>, dengan jabatan <strong>PARTTIME BARISTA</strong> pada divisi <strong>BAR</strong>. Selanjutnya disebut <strong>PEGAWAI</strong>.</td></tr></tbody></table><p style=\"margin:0 0 8px;text-align:justify;line-height:1.85\">Kontrak ini merupakan <strong>perpanjangan dari Kontrak 1</strong> (No. K2) setelah PEGAWAI dinyatakan <strong>lulus evaluasi masa training</strong>.</p><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 1<br>Status dan Masa Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI diterima sebagai <strong>Pegawai Kontrak 2 (Lanjutan)</strong> untuk jabatan <strong>PARTTIME BARISTA</strong> di divisi <strong>BAR</strong>, ditempatkan di Namua Coffee and Eatery, Rembang.</li><li style=\"margin-bottom:5px\">Masa kerja selama <strong>6 bulan</strong>, terhitung sejak <strong>8 Oktober 2025</strong> hingga <strong>8 April 2026</strong>.</li><li style=\"margin-bottom:5px\">Evaluasi dilakukan pada bulan ke-6. Hasil evaluasi menentukan kelanjutan ke Kontrak 3.</li><li style=\"margin-bottom:5px\">Kriteria evaluasi: kinerja (KPI), kehadiran, disiplin, kemampuan kerja tim, dan perkembangan kompetensi.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 2<br>Jam dan Hari Kerja</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Hari kerja: <strong>26 (dua puluh enam) hari</strong> dalam setiap bulan kalender.</li><li style=\"margin-bottom:5px\">Jam kerja: <strong>9 (sembilan) jam per hari</strong>, termasuk 1 (satu) jam istirahat.</li><li style=\"margin-bottom:5px\">Sistem kerja: <strong>shift</strong> sesuai jadwal yang ditetapkan oleh Supervisor atau Head of Division (HOD).</li><li style=\"margin-bottom:5px\">PEGAWAI wajib hadir tepat waktu. Keterlambatan diperhitungkan sebagai pengurangan kompensasi harian sesuai kebijakan perusahaan.</li><li style=\"margin-bottom:5px\">PEGAWAI dapat ditempatkan pada jadwal hari libur nasional jika dibutuhkan operasional. Kompensasi Public Holiday berlaku sesuai Pasal 3.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 3<br>Kompensasi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kompensasi PEGAWAI terdiri atas:\r\n      <table style=\"width:100%;margin:6px 0 0;border-collapse:collapse;font-family:inherit;font-size:16px\">\r\n        <tbody><tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;width:38%;background:#f5f5f5\">Gaji Pokok Dasar</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 1.200.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Jabatan</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 204.000</strong> / bulan</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;background:#f5f5f5\">Tunjangan Objektif</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc\">: <strong>Rp 0</strong> / bulan</td>\r\n        </tr>\r\n        <tr style=\"background:#e8f0fe\">\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">Total Kompensasi Tetap</td>\r\n          <td style=\"padding:3px 8px;border:1px solid #ccc;font-weight:bold\">: <strong>Rp 1.404.000</strong> / bulan</td>\r\n        </tr>\r\n      </tbody></table></li><li style=\"margin-bottom:5px\">Uang Makan: <strong>Rp 0</strong> per shift kerja, dibayarkan setiap minggu pada bulan berikutnya.</li><li style=\"margin-bottom:5px\">Kompensasi tetap dibayarkan setiap tanggal 1–3 bulan berikutnya melalui transfer ke rekening bank PEGAWAI.</li><li style=\"margin-bottom:5px\"><strong>Public Holiday (PH):</strong> setiap hari libur nasional yang dijalani menghasilkan 1 jatah OFF kompensasi yang dapat diambil pada bulan berikutnya, berlaku selama 2 bulan, dan tidak dapat diuangkan. Penggunaan Public holiday harus seizin atasan dan tidak dapat digunakan di hari libur.</li><li style=\"margin-bottom:5px\">Tunjangan Hari Raya (THR): diberikan secara proporsional berdasarkan masa kerja kumulatif berdasarkan&nbsp;data dasar Gaji Pokok dengan memperhitungkan Kedisiplinan dan \r\nkinerja serta dengan mempertimbangkan kemampuan keuangan PERUSAHAAN.</li><li style=\"margin-bottom:5px\">Review kompensasi dari Kontrak 2 ke Kontrak 3 dilakukan berdasarkan hasil evaluasi — tidak berlaku otomatis.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 4<br>Lembur</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Lembur dilaksanakan atas permintaan dan persetujuan tertulis Supervisor/HOD.</li><li style=\"margin-bottom:5px\">Tarif lembur: <strong>Rp 8.000</strong> per jam. (meningkat dari Kontrak 1)</li><li style=\"margin-bottom:5px\">Lembur pada hari libur nasional yang tidak dijadwalkan sebelumnya: tarif sebesar <strong>1,5×</strong> tarif lembur normal.</li><li style=\"margin-bottom:5px\">Pembayaran lembur disatukan dengan kompensasi bulanan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 5<br>Ketidakhadiran dan Cuti Di Luar Tanggungan</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Sistem kompensasi PEGAWAI bersifat <strong>harian</strong>. Kompensasi dihitung berdasarkan hari kerja aktual dalam setiap bulan.</li><li style=\"margin-bottom:5px\">Ketidakhadiran tanpa keterangan diperhitungkan sebagai hari tidak masuk dan kompensasi tidak dibayarkan untuk hari tersebut.</li><li style=\"margin-bottom:5px\"><strong>Cuti Di Luar Tanggungan Perusahaan (CLTP):</strong> PEGAWAI dapat mengajukan izin tidak masuk kepada Supervisor/HOD. Izin yang disetujui dicatat sebagai CLTP; kompensasi untuk hari tersebut tidak dibayarkan.</li><li style=\"margin-bottom:5px\">Izin mendadak wajib dilaporkan sebelum jam mulai shift. Ketidakhadiran tanpa pemberitahuan selama 3 (tiga) hari kerja berturut-turut dianggap sebagai pengunduran diri sepihak.</li><li style=\"margin-bottom:5px\">Cuti Sakit: sakit lebih dari 2 (dua) hari berturut-turut wajib disertai surat keterangan dokter. Hari sakit diperhitungkan sebagai hari tidak masuk.</li><li style=\"margin-bottom:5px\"><strong>Izin Khusus</strong> (tidak mengurangi hari kerja aktual, diajukan kepada dan disetujui atasan): pernikahan diri sendiri (2 hari), kematian pasangan/anak/orang tua kandung (2 hari), kematian mertua/saudara kandung (1 hari), istri melahirkan bagi suami (1 hari).</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 6<br>Kewajiban Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Melaksanakan tugas sesuai jabatan dan instruksi atasan dengan penuh tanggung jawab dan integritas.</li><li style=\"margin-bottom:5px\">Mematuhi seluruh peraturan, SOP, dan standar pelayanan perusahaan.</li><li style=\"margin-bottom:5px\">Menjaga kebersihan, kerapian, dan keselamatan di area kerja.</li><li style=\"margin-bottom:5px\">Berpenampilan rapi sesuai standar perusahaan selama jam kerja.</li><li style=\"margin-bottom:5px\">Menjaga kerahasiaan resep, data pelanggan, dan informasi bisnis perusahaan selama masa kerja dan 6 bulan setelahnya.</li><li style=\"margin-bottom:5px\">Tidak merangkap pekerjaan di tempat lain tanpa izin tertulis perusahaan.</li><li style=\"margin-bottom:5px\">Melaporkan kepada atasan setiap kejadian atau kondisi yang berpotensi merugikan perusahaan.</li><li style=\"margin-bottom:5px\">Bersedia membantu pelatihan pegawai baru (Kontrak 1) di bawah supervisi atasan.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 7<br>Hak Pegawai</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Menerima kompensasi tetap dan uang makan tepat waktu sesuai kesepakatan.</li><li style=\"margin-bottom:5px\">Mendapatkan slip kompensasi setiap bulan.</li><li style=\"margin-bottom:5px\">Mendapatkan lingkungan kerja yang aman, layak, dan bebas diskriminasi.</li><li style=\"margin-bottom:5px\">Mendapatkan pelatihan/pengembangan kompetensi yang relevan dengan jabatan.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan evaluasi dan hasilnya secara tertulis.</li><li style=\"margin-bottom:5px\">Mendapatkan pemberitahuan minimum <strong>30 hari</strong> apabila kontrak tidak akan diperpanjang.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 8<br>Larangan dan Sanksi</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI dilarang: mencuri, menipu, memalsukan data, mengonsumsi alkohol/narkoba di tempat kerja, melakukan pelecehan atau kekerasan, dan membocorkan rahasia perusahaan.</li><li style=\"margin-bottom:5px\">Pelanggaran ringan (terlambat berulang, tidak mengikuti SOP): teguran lisan → teguran tertulis → Surat Peringatan (SP).</li><li style=\"margin-bottom:5px\">Pelanggaran berat (butir 1): Pemutusan Hubungan Kerja (PHK) seketika tanpa kompensasi.</li><li style=\"margin-bottom:5px\">3 (tiga) SP aktif dalam 1 (satu) periode kontrak menjadi dasar pengakhiran kontrak.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 9<br>Pengunduran Diri</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">PEGAWAI yang mengundurkan diri wajib memberitahu secara tertulis minimum <strong>30 (tiga puluh) hari</strong> sebelum tanggal efektif.</li><li style=\"margin-bottom:5px\">Pengunduran diri sebelum masa kontrak berakhir tanpa alasan yang dapat diterima dikenakan denda sebesar <strong>Rp 750.000,-</strong>.</li><li style=\"margin-bottom:5px\">PEGAWAI tetap melaksanakan tugas dan kewajibannya penuh hingga batas waktu pengunduran diri berlaku.</li><li style=\"margin-bottom:5px\">PEGAWAI wajib menyelesaikan serah terima tugas dan mengembalikan seluruh inventaris perusahaan dalam kondisi baik.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 10<br>Force Majeure</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Dalam kondisi darurat (bencana alam, pandemi, kebijakan pemerintah) yang menyebabkan operasional terganggu, para pihak bermusyawarah dalam 14 (empat belas) hari untuk mencari solusi bersama.</li><li style=\"margin-bottom:5px\">Pemotongan kompensasi akibat force majeure tidak melebihi <strong>25%</strong> dari kompensasi tetap dan harus atas kesepakatan bersama.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 11<br>Pengakhiran Kontrak</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Kontrak berakhir sendirinya pada tanggal <strong>8 April 2026</strong>.</li><li style=\"margin-bottom:5px\">PERUSAHAAN dapat mengakhiri kontrak sebelum waktunya apabila PEGAWAI melakukan pelanggaran berat atau tidak memenuhi standar kinerja minimum setelah evaluasi dan peringatan tertulis.</li><li style=\"margin-bottom:5px\">Berakhirnya PKWT secara alami tidak menimbulkan kewajiban pesangon sesuai PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">PHK karena pelanggaran berat dapat dilakukan seketika tanpa pemberitahuan dan kompensasi.</li></ol><p style=\"text-align:center;font-family:Arial,sans-serif;font-size:16px;font-weight:bold;margin:22px 0 6px;letter-spacing:.3px;text-transform:uppercase;text-decoration:underline\">Pasal 12<br>Ketentuan Lain</p><ol style=\"margin:4px 0 10px;padding-left:22px;line-height:1.85\"><li style=\"margin-bottom:5px\">Peraturan Perusahaan dan SOP yang berlaku merupakan satu kesatuan yang tidak terpisahkan dari perjanjian ini.</li><li style=\"margin-bottom:5px\">Perubahan isi perjanjian hanya sah apabila dibuat secara tertulis dan ditandatangani oleh kedua belah pihak.</li><li style=\"margin-bottom:5px\">Hal-hal yang belum diatur dalam perjanjian ini akan diatur kemudian atas kesepakatan para pihak dalam suatu amandemen.</li><li style=\"margin-bottom:5px\">Perjanjian ini tunduk pada hukum yang berlaku di Indonesia, khususnya UU No. 11 Tahun 2020 tentang Cipta Kerja jo. PP No. 35 Tahun 2021.</li><li style=\"margin-bottom:5px\">Perselisihan diselesaikan secara musyawarah. Apabila tidak tercapai, diselesaikan melalui mekanisme ketenagakerjaan yang berlaku.</li></ol></div></div>', '', 67, '2026-04-24 18:04:28', 67, '2026-04-24 18:04:28', '2026-05-07 23:53:51');
